n_qubits = 150
print(f"Total stabilizers: {len(stabilizers)}")

# Use Stim's tableau synthesis
stim_stabs = []
for s in stabilizers:
    stim_stabs.append(stim.PauliString(s))

try:
    tableau = stim.Tableau.from_stabilizers(stim_stabs, allow_redundant=True, allow_underconstrained=True)
    print("Tableau created successfully!")
    
    # Generate circuit using graph_state method
    circuit = tableau.to_circuit(method='graph_state')
    print(f"Circuit instructions: {len(circuit)}")
    
    # Save the circuit
    with open("candidate.stim", "w") as f:
        f.write(str(circuit))
    print("Saved to candidate.stim")
    
except Exception as e:
    print(f"Error: {e}")
